674: void Utility::removeUpgrade(RequestOrResponseHeaderMap& headers,
675:                             const std::vector<Matchers::StringMatcherPtr>& matchers) {
676:   if (headers.Upgrade()) {
677:     std::vector<absl::string_view> tokens =
678:         Envoy::StringUtil::splitToken(headers.getUpgradeValue(), ",", false, true);
679: 
680:     auto end = std::remove_if(tokens.begin(), tokens.end(), [&](absl::string_view token) {
681:       return std::any_of(
682:           matchers.begin(), matchers.end(),
683:           [&token](const Matchers::StringMatcherPtr& matcher) { return matcher->match(token); });
684:     });
685: 
686:     const std::string new_value = absl::StrJoin(tokens.begin(), end, ",");
687: 
688:     if (new_value.empty()) {
689:       headers.removeUpgrade();
690:     } else {
691:       headers.setUpgrade(new_value);
692:     }
693:   }
694: }
