696: void Utility::removeConnectionUpgrade(RequestOrResponseHeaderMap& headers,
697:                                       const StringUtil::CaseUnorderedSet& tokens_to_remove) {
698:   if (headers.Connection()) {
699:     const std::string new_value =
700:         StringUtil::removeTokens(headers.getConnectionValue(), ",", tokens_to_remove, ",");
701:     if (new_value.empty()) {
702:       headers.removeConnection();
703:     } else {
704:       headers.setConnection(new_value);
705:     }
706:   }
