982: void DownstreamFilterManager::sendLocalReply(
983:     Code code, absl::string_view body,
984:     const std::function<void(ResponseHeaderMap& headers)>& modify_headers,
985:     const absl::optional<Grpc::Status::GrpcStatus> grpc_status, absl::string_view details) {
986:   ASSERT(!state_.under_on_local_reply_);
987:   const bool is_head_request = state_.is_head_request_;
988:   const bool is_grpc_request = state_.is_grpc_request_;
989: 
990:   // Stop filter chain iteration if local reply was sent while filter decoding or encoding callbacks
991:   // are running.
992:   if (state_.filter_call_state_ & FilterCallState::IsDecodingMask) {
993:     state_.decoder_filter_chain_aborted_ = true;
994:   } else if (state_.filter_call_state_ & FilterCallState::IsEncodingMask) {
995:     state_.encoder_filter_chain_aborted_ = true;
996:   }
997:   // When independent half-close is enabled local reply always stops decoder filter chain.
998:   if (filter_manager_callbacks_.isHalfCloseEnabled()) {
999:     state_.decoder_filter_chain_aborted_ = true;
1000:   }
1001: 
1002:   streamInfo().setResponseCodeDetails(details);
1003:   StreamFilterBase::LocalReplyData data{code, grpc_status, details, false};
1004:   onLocalReply(data);
1005:   if (data.reset_imminent_) {
1006:     ENVOY_STREAM_LOG(debug, "Resetting stream due to {}. onLocalReply requested reset.", *this,
1007:                      details);
1008:     filter_manager_callbacks_.resetStream(Http::StreamResetReason::LocalReset, "");
1009:     return;
1010:   }
1011: 
1012:   if (!filter_manager_callbacks_.responseHeaders().has_value() &&
1013:       (!filter_manager_callbacks_.informationalHeaders().has_value() ||
1014:        !(state_.filter_call_state_ & FilterCallState::IsEncodingMask))) {
1015:     // If the response has not started at all, or if the only response so far is an informational
1016:     // 1xx that has already been fully processed, send the response through the filter chain.
1017: 
1018:     if (auto cb = filter_manager_callbacks_.downstreamCallbacks(); cb.has_value()) {
1019:       // The initial route maybe never be set or the cached route maybe cleared by the filters.
1020:       // This will force route refreshment if there is not a cached route to avoid potential
1021:       // route refreshment in the response filter chain.
1022:       cb->route(nullptr);
1023:     }
1024: 
1025:     // We only prepare a local reply to execute later if we're actively
1026:     // invoking filters to avoid re-entrant in filters.
1027:     if (state_.filter_call_state_ & FilterCallState::IsDecodingMask) {
1028:       prepareLocalReplyViaFilterChain(is_grpc_request, code, body, modify_headers, is_head_request,
1029:                                       grpc_status, details);
1030:     } else {
