145: void HeaderParser::evaluateHeaders(Http::HeaderMap& headers,
146:                                    const Formatter::HttpFormatterContext& context,
147:                                    const StreamInfo::StreamInfo* stream_info) const {
148:   // Removing headers in the headers_to_remove_ list first makes
149:   // remove-before-add the default behavior as expected by users.
150:   for (const auto& header : headers_to_remove_) {
151:     headers.remove(header);
152:   }
153: 
154:   // Temporary storage to hold evaluated values of headers to add and replace. This is required
155:   // to execute all formatters using the original received headers.
156:   // Only after all the formatters produced the new values of the headers, the headers are set.
157:   // absl::InlinedVector is optimized for 4 headers. After that it behaves as normal std::vector.
158:   // It is assumed that most of the use cases will add or modify fairly small number of headers
159:   // (<=4). If this assumption changes, the number of inlined capacity should be increased.
160:   // header_formatter_speed_test.cc provides micro-benchmark for evaluating speed of adding and
161:   // replacing headers and should be used when modifying the code below to access the performance
162:   // impact of code changes.
163:   absl::InlinedVector<std::pair<const Http::LowerCaseString&, const std::string>, 4> headers_to_add,
164:       headers_to_overwrite;
165:   // value_buffer is used only when stream_info is a valid pointer and stores header value
166:   // created by a formatter. It is declared outside of 'for' loop for performance reason to avoid
167:   // stack allocation and unnecessary std::string's memory adjustments for each iteration. The
168:   // actual value of the header is accessed via 'value' variable which is initialized differently
169:   // depending whether stream_info and valid or nullptr. Based on performance tests implemented in
170:   // header_formatter_speed_test.cc this approach strikes the best balance between performance and
171:   // readability.
172:   std::string value_buffer;
173:   for (const auto& [key, entry] : headers_to_add_) {
174:     absl::string_view value;
175:     if (stream_info != nullptr) {
176:       value_buffer = entry->formatter_->formatWithContext(context, *stream_info);
177:       value = value_buffer;
178:     } else {
179:       value = entry->original_value_;
180:     }
181:     if (!value.empty() || entry->add_if_empty_) {
