183: Http::FilterHeadersStatus HeaderMutation::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
184:   Formatter::HttpFormatterContext context{encoder_callbacks_->requestHeaders().ptr(), &headers};
185:   config_->mutations().mutateResponseHeaders(headers, context, encoder_callbacks_->streamInfo());
186: 
187:   // Note if the filter before this one has send local reply then the decodeHeaders() will not be
188:   // be called and the route config will not be initialized. Try it again here and it will be
189:   // no-op if already initialized.
190:   maybeInitializeRouteConfigs(encoder_callbacks_);
191: 
192:   for (const PerRouteHeaderMutation& route_config : route_configs_) {
193:     route_config.mutations().mutateResponseHeaders(headers, context,
194:                                                    encoder_callbacks_->streamInfo());
195:   }
196: 
197:   return Http::FilterHeadersStatus::Continue;
198: }
