1244: void FilterManager::encodeHeaders(ActiveStreamEncoderFilter* filter, ResponseHeaderMap& headers,
1245:                                   bool end_stream) {
1246:   // See encodeHeaders() comments in envoy/http/filter.h for why the 1xx precondition holds.
1247:   ASSERT(!CodeUtility::is1xx(Utility::getResponseStatus(headers)) ||
1248:          Utility::getResponseStatus(headers) == enumToInt(Http::Code::SwitchingProtocols));
1249:   filter_manager_callbacks_.resetIdleTimer();
1250:   disarmRequestTimeout();
1251: 
1252:   // Headers filter iteration should always start with the next filter if available.
1253:   StreamEncoderFilters::Iterator entry =
1254:       commonEncodePrefix(filter, end_stream, FilterIterationStartState::AlwaysStartFromNext);
1255:   StreamEncoderFilters::Iterator continue_data_entry = encoder_filters_.end();
1256: 
1257:   for (; entry != encoder_filters_.end(); entry++) {
1258:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
1259:     ASSERT(!(state_.filter_call_state_ & FilterCallState::EncodeHeaders));
1260:     state_.filter_call_state_ |= FilterCallState::EncodeHeaders;
1261:     (*entry)->end_stream_ = (end_stream && continue_data_entry == encoder_filters_.end());
1262:     if ((*entry)->end_stream_) {
1263:       state_.filter_call_state_ |= FilterCallState::EndOfStream;
1264:     }
1265:     FilterHeadersStatus status = (*entry)->handle_->encodeHeaders(headers, (*entry)->end_stream_);
1266:     if (state_.encoder_filter_chain_aborted_) {
1267:       ENVOY_STREAM_LOG(trace,
1268:                        "encodeHeaders filter iteration aborted due to local reply: filter={}",
1269:                        *this, (*entry)->filter_context_.config_name);
1270:       status = FilterHeadersStatus::StopIteration;
1271:     }
1272: 
1273:     ASSERT(!(status == FilterHeadersStatus::ContinueAndDontEndStream && !(*entry)->end_stream_),
1274:            "Filters should not return FilterHeadersStatus::ContinueAndDontEndStream from "
1275:            "encodeHeaders when end_stream is already false");
1276: 
1277:     state_.filter_call_state_ &= ~FilterCallState::EncodeHeaders;
1278:     if ((*entry)->end_stream_) {
1279:       state_.filter_call_state_ &= ~FilterCallState::EndOfStream;
1280:     }
1281:     ENVOY_STREAM_LOG(trace, "encode headers called: filter={} status={}", *this,
1282:                      (*entry)->filter_context_.config_name, static_cast<uint64_t>(status));
1283: 
1284:     (*entry)->processed_headers_ = true;
1285: 
1286:     const auto continue_iteration = (*entry)->commonHandleAfterHeadersCallback(status, end_stream);
1287: 
1288:     // If this filter ended the stream, encodeComplete() should be called for it.
1289:     if ((*entry)->end_stream_) {
1290:       (*entry)->handle_->encodeComplete();
1291:     }
1292: 
1293:     if (!continue_iteration) {
1294:       if (!(*entry)->end_stream_) {
1295:         maybeContinueEncoding(continue_data_entry);
1296:       }
1297:       return;
1298:     }
1299: 
1300:     // Here we handle the case where we have a header only response, but a filter adds a body
1301:     // to it. We need to not raise end_stream = true to further filters during inline iteration.
1302:     if (end_stream && buffered_response_data_ && continue_data_entry == encoder_filters_.end()) {
1303:       continue_data_entry = entry;
1304:     }
1305:   }
1306: 
1307:   // Check if the filter chain above did not remove critical headers or set malformed header values.
1308:   // We could do this at the codec in order to prevent other places than the filter chain from
1309:   // removing critical headers, but it will come with the implementation complexity.
1310:   // See the previous attempt (#15658) for detail, and for now we choose to protect only against
1311:   // filter chains.
1312:   const auto status = HeaderUtility::checkRequiredResponseHeaders(headers);
1313:   if (!status.ok()) {
1314:     // If the check failed, then we reply with BadGateway, and stop the further processing.
1315:     sendLocalReply(
1316:         Http::Code::BadGateway, status.message(), nullptr, absl::nullopt,
1317:         absl::StrCat(StreamInfo::ResponseCodeDetails::get().FilterRemovedRequiredResponseHeaders,
1318:                      "{", StringUtil::replaceAllEmptySpace(status.message()), "}"));
1319:     return;
1320:   }
1321: 
1322:   const bool modified_end_stream = (end_stream && continue_data_entry == encoder_filters_.end());
1323:   state_.non_100_response_headers_encoded_ = true;
1324:   filter_manager_callbacks_.encodeHeaders(headers, modified_end_stream);
1325:   if (state_.saw_downstream_reset_) {
1326:     return;
1327:   }
1328:   maybeEndEncode(modified_end_stream);
1329: 
1330:   if (!modified_end_stream) {
1331:     maybeContinueEncoding(continue_data_entry);
1332:   }
