960:   }
961:   if (filter_iteration_start_state == FilterIterationStartState::CanStartFromCurrent &&
962:       (*(filter->entry()))->iterate_from_current_filter_) {
963:     // The filter iteration has been stopped for all frame types, and now the iteration continues.
964:     // The current filter's callback function has not been called. Call it now.
965:     return filter->entry();
