1239: // Called when the per try timeout is hit but we didn't reset the request
1240: // (hedge_on_per_try_timeout enabled).
1241: void Filter::onSoftPerTryTimeout(UpstreamRequest& upstream_request) {
1242:   ASSERT(!upstream_request.retried());
1243:   // Track this as a timeout for outlier detection purposes even though we didn't
1244:   // cancel the request yet and might get a 2xx later.
1245:   updateOutlierDetection(Upstream::Outlier::Result::LocalOriginTimeout, upstream_request,
1246:                          absl::optional<uint64_t>(enumToInt(timeout_response_code_)));
1247:   upstream_request.outlierDetectionTimeoutRecorded(true);
1248: 
1249:   if (!downstream_response_started_ && retry_state_) {
1250:     RetryStatus retry_status = retry_state_->shouldHedgeRetryPerTryTimeout(
1251:         [this, can_use_http3 = upstream_request.upstreamStreamOptions().can_use_http3_]() -> void {
1252:           // Without any knowledge about what's going on in the connection pool, retry the request
1253:           // with the safest settings which is no early data but keep using or not using alt-svc as
1254:           // before. In this way, QUIC won't be falsely marked as broken.
1255:           doRetry(/*can_send_early_data*/ false, can_use_http3, TimeoutRetry::Yes);
1256:         });
1257: 
1258:     if (retry_status == RetryStatus::Yes) {
1259:       runRetryOptionsPredicates(upstream_request);
1260:       pending_retries_++;
1261: 
1262:       // Don't increment upstream_host->stats().rq_error_ here, we'll do that
1263:       // later if 1) we hit global timeout or 2) we get bad response headers
1264:       // back.
1265:       upstream_request.retried(true);
1266: 
1267:       // TODO: cluster stat for hedge attempted.
1268:     } else if (retry_status == RetryStatus::NoOverflow) {
1269:       callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::UpstreamOverflow);
1270:     } else if (retry_status == RetryStatus::NoRetryLimitExceeded) {
1271:       callbacks_->streamInfo().setResponseFlag(
1272:           StreamInfo::CoreResponseFlag::UpstreamRetryLimitExceeded);
1273:     }
1274:   }
1275: }
